module div_16bit(
    input [15:0] A,
    input [7:0] B,
    output [15:0] result,
    output [15:0] odd
);

    reg [15:0] a_reg;
    reg [7:0] b_reg;
    reg [15:0] result_reg;
    reg [15:0] odd_reg;

    always @(*) begin
        a_reg = A;
        b_reg = B;
    end

    always @(*) begin
        reg [7:0] remainder;
        reg [15:0] quotient;
        integer i;

        quotient = 16'b0;
        remainder = 8'b0;

        remainder = a_reg[15:8];

        for (i = 8; i >= 1; i = i - 1) begin
            if (remainder >= b_reg) begin
                quotient[i-1] = 1'b1;
                remainder = remainder - b_reg;
            end else begin
                quotient[i-1] = 1'b0;
            end
            if (i > 1) begin
                remainder = {remainder[6:0], a_reg[i-2]};
            end
        end

        result_reg = quotient;
        odd_reg = {8'b0, remainder};
    end

    assign result = result_reg;
    assign odd = odd_reg;

endmodule

