module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

    parameter MUL2_DIV_CLK = 7;

    reg [2:0] cnt;
    reg clk_div_p;
    reg clk_div_n;

    // Counter on positive edge, cycles 0 through MUL2_DIV_CLK-1
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            cnt <= 3'd0;
        else if (cnt == MUL2_DIV_CLK - 1)
            cnt <= 3'd0;
        else
            cnt <= cnt + 1'd1;
    end

    // Positive-edge clocked divided clock
    // High for 3 source cycles (cnt 0,1,2), low for 4 source cycles (cnt 3..6)
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            clk_div_p <= 1'b0;
        else if (cnt < (MUL2_DIV_CLK / 2))
            clk_div_p <= 1'b1;
        else
            clk_div_p <= 1'b0;
    end

    // Negative-edge clocked divided clock (phase shifted by half source period)
    // Same logic as clk_div_p but sampled on falling edges, shifting by 0.5T
    always @(negedge clk or negedge rst_n) begin
        if (!rst_n)
            clk_div_n <= 1'b0;
        else if (cnt < (MUL2_DIV_CLK / 2))
            clk_div_n <= 1'b1;
        else
            clk_div_n <= 1'b0;
    end

    // OR the two phase-shifted clocks to produce fractional divided output.
    // clk_div_p rises at posedge of cnt=0, falls at posedge of cnt=3 (3.0T high).
    // clk_div_n rises at negedge of cnt=6 (=6.5T), falls at negedge of cnt=2 (=2.5T).
    // OR result: high 3.5T, low 3.5T -> period = 7T -> divide by 3.5
    assign clk_div = clk_div_p | clk_div_n;

endmodule

